// Los datos de la cuenta ya no viven solo en el celular: cada lectura/escritura
// va a la tabla "app_data" de Supabase, protegida por RLS (cada usuario solo ve
// lo suyo). Esto es lo que hace que una cuenta creada NO se pierda al recargar,
// cambiar de celular, o si el navegador borra el almacenamiento local.
// Guarda el último error real que devolvió Supabase, para poder mostrarlo en
// pantalla y diagnosticar (en vez de solo saber que "algo falló").
let lastStorageError = null;
// Cuando un trabajador inicia sesión en un dispositivo donde el
// administrador nunca ha iniciado sesión, no existe una sesión real de
// Supabase Auth. En ese caso usamos estas credenciales (validadas por el
// backend en cada llamada) para leer/escribir los datos del negocio
// mediante funciones seguras (RPC), en vez de la sesión normal.
const WORKER_AUTH_KEY = "chefwillys_worker_auth";
let workerAuthState = null; // { ownerUserId, username, password, workerId, workerName, role } | null

async function getUserId() {
  try {
    const { data } = await supabase.auth.getSession();
    return data?.session?.user?.id || null;
  } catch {
    return null;
  }
}
async function safeGet(key) {
  try {
    const userId = await getUserId();
    if (userId) {
      const { data, error } = await supabase
        .from("app_data")
        .select("value")
        .eq("user_id", userId)
        .eq("key", key)
        .maybeSingle();
      if (error) {
        lastStorageError = error.message;
        return null;
      }
      if (!data) return null;
      lastStorageError = null;
      return JSON.stringify(data.value);
    }
    if (workerAuthState) {
      const { data, error } = await supabase.rpc("worker_get_data", {
        p_owner_user_id: workerAuthState.ownerUserId,
        p_username: workerAuthState.username,
        p_password: workerAuthState.password,
        p_key: key,
      });
      if (error) {
        lastStorageError = error.message;
        return null;
      }
      if (data === null || data === undefined) return null;
      lastStorageError = null;
      return JSON.stringify(data);
    }
    lastStorageError = "No hay una sesión activa de Supabase en este dispositivo.";
    return null;
  } catch (e) {
    lastStorageError = e?.message || String(e);
    return null;
  }
}
async function safeSet(key, value) {
  try {
    const userId = await getUserId();
    if (userId) {
      const { error } = await supabase
        .from("app_data")
        .upsert(
          { user_id: userId, key, value: JSON.parse(value), updated_at: new Date().toISOString() },
          { onConflict: "user_id,key" }
        );
      if (error) {
        lastStorageError = error.message;
        return false;
      }
      lastStorageError = null;
      return true;
    }
    if (workerAuthState) {
      const { data, error } = await supabase.rpc("worker_set_data", {
        p_owner_user_id: workerAuthState.ownerUserId,
        p_username: workerAuthState.username,
        p_password: workerAuthState.password,
        p_key: key,
        p_value: JSON.parse(value),
      });
      if (error || !data) {
        lastStorageError = error?.message || "No se pudo guardar.";
        return false;
      }
      lastStorageError = null;
      return true;
    }
    lastStorageError = "No hay una sesión activa de Supabase en este dispositivo.";
    return false;
  } catch (e) {
    lastStorageError = e?.message || String(e);
    return false;
  }
}

// Revisa cada cierto tiempo si hay una versión más nueva de la app publicada
// (compara /version.json, que se actualiza solo con cada despliegue en
// Vercel). Si hay una nueva, avisa con una barra para recargar -- así los
// cambios subidos a GitHub llegan a todos los dispositivos sin que nadie
// tenga que borrar caché manualmente.
export function UpdateBanner() {
  const [updateAvailable, setUpdateAvailable] = useState(false);
  const initialVersion = useRef(null);

  useEffect(() => {
    let cancelled = false;

    async function checkVersion() {
      try {
        const res = await fetch("/version.json?t=" + Date.now(), { cache: "no-store" });
        if (!res.ok) return;
        const data = await res.json();
        if (cancelled) return;
        if (initialVersion.current === null) {
          initialVersion.current = data.version;
        } else if (data.version !== initialVersion.current) {
          setUpdateAvailable(true);
        }
      } catch {
        // sin conexión momentánea; no pasa nada, se reintenta después
      }
    }

    checkVersion();
    const interval = setInterval(checkVersion, 45000);
    function onVisible() {
      if (document.visibilityState === "visible") checkVersion();
    }
    document.addEventListener("visibilitychange", onVisible);

    return () => {
      cancelled = true;
      clearInterval(interval);
      document.removeEventListener("visibilitychange", onVisible);
    };
  }, []);

  if (!updateAvailable) return null;

  return (
    <div
      style={{
        position: "fixed",
        top: "calc(10px + env(safe-area-inset-top))",
        left: "50%",
        transform: "translateX(-50%)",
        zIndex: 99999,
        background: "#1a1a1a",
        border: `1.5px solid ${ORANGE}`,
        borderRadius: 14,
        padding: "10px 10px 10px 16px",
        display: "flex",
        alignItems: "center",
        gap: 12,
        boxShadow: "0 8px 24px rgba(0,0,0,0.5)",
        maxWidth: "calc(100vw - 24px)",
        fontFamily: "system-ui, -apple-system, sans-serif",
      }}
    >
      <span style={{ color: "#fff", fontSize: 13, fontWeight: 700, whiteSpace: "nowrap" }}>🔄 Hay una versión nueva</span>
      <button
        onClick={() => window.location.reload()}
        style={{ background: ORANGE, border: "none", borderRadius: 10, padding: "8px 14px", color: "#fff", fontWeight: 800, fontSize: 12.5, whiteSpace: "nowrap" }}
      >
        Actualizar ahora
      </button>
    </div>
  );
}

