function CustomLineRow({ line, onDec, onInc }) {
  return (
    <div style={{ background: "#1c1c1c", borderRadius: 8, padding: "6px 8px", display: "flex", alignItems: "center", justifyContent: "space-between", gap: 6 }}>
      <span style={{ color: line.sin.length ? "#f5a524" : "#888", fontSize: 10.5, lineHeight: 1.3, flex: 1 }}>
        {line.sin.length ? line.sin.join(", ") : "Sin cambios"}
      </span>
      <div style={{ display: "flex", alignItems: "center", gap: 5, flexShrink: 0 }}>
        <button onClick={onDec} style={{ width: 22, height: 22, borderRadius: 6, border: "none", background: "#2a2a2a", color: "#fff", display: "flex", alignItems: "center", justifyContent: "center" }}>
          <Minus size={11} />
        </button>
        <span style={{ minWidth: 12, textAlign: "center", fontWeight: 700, fontSize: 12 }}>{line.qty}</span>
        <button onClick={onInc} style={{ width: 22, height: 22, borderRadius: 6, border: "none", background: ORANGE, color: "#fff", display: "flex", alignItems: "center", justifyContent: "center" }}>
          <Plus size={11} />
        </button>
      </div>
    </div>
  );
}

function PreparacionView({ pedidos, savePedidos, workerId, workerName, onRefresh, refreshing }) {
  const today = todayKey();
  const todays = pedidos.filter((p) => p.dateKey === today);
  const pendientes = todays.filter((p) => p.estadoCocina === "pendiente").sort((a, b) => (a.timestamp < b.timestamp ? -1 : 1));
  const preparados = todays.filter((p) => p.estadoCocina === "preparado").sort((a, b) => (a.timestamp < b.timestamp ? 1 : -1));

  async function marcarPreparado(id) {
    const next = pedidos.map((p) =>
      p.id === id
        ? { ...p, estadoCocina: "preparado", preparedAt: new Date().toISOString(), preparedByWorkerId: workerId || null, preparedByWorkerName: workerName || null }
        : p
    );
    await savePedidos(next);
  }

  async function deshacer(id) {
    const next = pedidos.map((p) => (p.id === id ? { ...p, estadoCocina: "pendiente", preparedAt: null, preparedByWorkerId: null, preparedByWorkerName: null } : p));
    await savePedidos(next);
  }

  return (
    <div style={{ padding: "16px 18px" }}>
      <div style={{ display: "flex", alignItems: "flex-start", justifyContent: "space-between", marginBottom: 20 }}>
        <div>
          <h2 style={{ margin: "0 0 4px", fontSize: 20 }}>Preparación</h2>
          <div style={{ color: "#999", fontSize: 14 }}>
            {pendientes.length} pendiente{pendientes.length !== 1 ? "s" : ""} · {preparados.length} preparado{preparados.length !== 1 ? "s" : ""}
          </div>
        </div>
        <button
          onClick={onRefresh}
          disabled={refreshing}
          style={{ background: "#141414", border: "1px solid #2a2a2a", borderRadius: 12, width: 42, height: 42, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}
        >
          <RefreshCw size={18} color={ORANGE} className={refreshing ? "spin-icon" : ""} />
        </button>
      </div>

      <div style={{ color: "#f87171", fontSize: 13, fontWeight: 800, letterSpacing: 1, marginBottom: 10 }}>🔴 FALTA PREPARAR</div>

      {pendientes.length === 0 && (
        <div style={{ color: "#666", textAlign: "center", padding: "24px 0", fontSize: 15, marginBottom: 20 }}>
          No hay pedidos pendientes. ¡Al día!
        </div>
      )}

      {pendientes.map((p) => (
        <div key={p.id} style={{ background: "#241414", border: "1px solid #7a3030", borderRadius: 16, padding: 16, marginBottom: 14 }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
            <span style={{ fontWeight: 800, fontSize: 17 }}>Pedido #{p.numero}</span>
            <span style={{ color: "#999", fontSize: 13 }}>{new Date(p.timestamp).toLocaleTimeString("es-CO", { hour: "2-digit", minute: "2-digit" })}</span>
          </div>
          {p.domicilio && (
            <div style={{ display: "inline-block", background: ORANGE, color: "#fff", fontSize: 12, fontWeight: 700, borderRadius: 6, padding: "3px 8px", marginBottom: 10 }}>
              🛵 Domicilio
            </div>
          )}
          {p.items.map((it, idx) => (
            <div key={idx} style={{ fontSize: 16, fontWeight: 600, padding: "4px 0" }}>
              <span style={{ color: ORANGE, fontWeight: 800 }}>{it.qty}x</span> {it.name}
              {it.sin && it.sin.length > 0 && (
                <div style={{ color: "#f5a524", fontSize: 12.5, fontWeight: 700, marginLeft: 20 }}>⚠️ {it.sin.join(", ")}</div>
              )}
            </div>
          ))}
          <button
            onClick={() => marcarPreparado(p.id)}
            style={{ width: "100%", marginTop: 12, background: "#22c55e", border: "none", borderRadius: 12, padding: "16px", color: "#fff", fontWeight: 800, fontSize: 16, display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}
          >
            <Check size={20} /> Marcar como preparado
          </button>
        </div>
      ))}

      <div style={{ color: "#4ade80", fontSize: 13, fontWeight: 800, letterSpacing: 1, margin: "24px 0 10px" }}>✅ YA PREPARADOS</div>

      {preparados.length === 0 && (
        <div style={{ color: "#666", textAlign: "center", padding: "20px 0", fontSize: 14 }}>Todavía no has preparado ningún pedido hoy.</div>
      )}

      {preparados.map((p) => (
        <div key={p.id} style={{ background: "#141414", border: "1px solid #2f6b46", borderRadius: 16, padding: 14, marginBottom: 10, opacity: 0.75 }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 6 }}>
            <span style={{ fontWeight: 700, fontSize: 15, textDecoration: "line-through", color: "#aaa" }}>Pedido #{p.numero}</span>
            <span style={{ color: "#4ade80", fontSize: 12, fontWeight: 700 }}>
              Listo {p.preparedAt ? new Date(p.preparedAt).toLocaleTimeString("es-CO", { hour: "2-digit", minute: "2-digit" }) : ""}
            </span>
          </div>
          {p.items.map((it, idx) => (
            <div key={idx} style={{ fontSize: 13, color: "#999", padding: "1px 0" }}>
              {it.qty}x {it.name}{it.sin && it.sin.length > 0 ? ` (${it.sin.join(", ")})` : ""}
            </div>
          ))}
          <button onClick={() => deshacer(p.id)} style={{ background: "none", border: "none", color: "#888", fontSize: 12, marginTop: 6, textDecoration: "underline" }}>
            Deshacer
          </button>
        </div>
      ))}
    </div>
  );
}

function DomiciliarioView({ pedidos, savePedidos, workerId, workerName, onRefresh, refreshing }) {
  const [tab, setTab] = useState("pendientes"); // pendientes | entregados | todos
  const today = todayKey();
  const todays = pedidos.filter((p) => p.dateKey === today && p.domicilio);
  const pendientes = todays.filter((p) => p.estadoEntrega === "pendiente").sort((a, b) => (a.timestamp < b.timestamp ? -1 : 1));
  const entregados = todays.filter((p) => p.estadoEntrega === "entregado").sort((a, b) => (a.timestamp < b.timestamp ? 1 : -1));
  // El domiciliario solo debe caja en efectivo -- lo pagado con transferencia o tarjeta no pasa por sus manos.
  const dineroPendiente = todays
    .filter((p) => !p.dineroEntregado && (!p.metodoPago || p.metodoPago === "efectivo"))
    .reduce((s, p) => s + p.total, 0);

  async function marcarEntregado(id) {
    const next = pedidos.map((p) =>
      p.id === id
        ? { ...p, estadoEntrega: "entregado", deliveredAt: new Date().toISOString(), deliveredByWorkerId: workerId || null, deliveredByWorkerName: workerName || null }
        : p
    );
    await savePedidos(next);
  }

  async function deshacer(id) {
    const next = pedidos.map((p) => (p.id === id ? { ...p, estadoEntrega: "pendiente", deliveredAt: null, deliveredByWorkerId: null, deliveredByWorkerName: null } : p));
    await savePedidos(next);
  }

  const listado = tab === "pendientes" ? pendientes : tab === "entregados" ? entregados : todays;

  return (
    <div style={{ padding: "16px 18px" }}>
      {dineroPendiente > 0 && (
        <div style={{ background: "#1e3a8a", borderRadius: 16, padding: "16px 18px", marginBottom: 16, display: "flex", alignItems: "center", gap: 14 }}>
          <div style={{ width: 46, height: 46, borderRadius: "50%", border: "2px solid #60a5fa", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
            <Banknote size={20} color="#dbeafe" />
          </div>
          <div style={{ flex: 1 }}>
            <div style={{ color: "#dbeafe", fontSize: 12.5, fontWeight: 700 }}>Dinero que aún debes a caja</div>
            <div style={{ color: "#fff", fontWeight: 900, fontSize: 26 }}>{money(dineroPendiente)}</div>
          </div>
          <ChevronLeft size={20} color="#93c5fd" style={{ transform: "rotate(180deg)" }} />
        </div>
      )}

      <div style={{ background: "#141414", border: "1px solid #202020", borderRadius: 16, padding: "14px 16px", marginBottom: 14, display: "flex", alignItems: "center", gap: 12 }}>
        <div style={{ width: 42, height: 42, borderRadius: 12, background: "rgba(245,130,31,0.15)", border: "1px solid rgba(245,130,31,0.4)", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
          <Package size={20} color={ORANGE} />
        </div>
        <div style={{ flex: 1, minWidth: 0 }}>
          <div style={{ fontWeight: 800, fontSize: 16.5 }}>Domicilios</div>
          <div style={{ color: "#999", fontSize: 12 }}>
            {pendientes.length} por entregar · {entregados.length} entregado{entregados.length !== 1 ? "s" : ""}
          </div>
        </div>
        <button
          onClick={onRefresh}
          disabled={refreshing}
          style={{ background: "#1a1a1a", border: "1px solid #2a2a2a", borderRadius: 10, padding: "9px 12px", display: "flex", alignItems: "center", gap: 6, flexShrink: 0 }}
        >
          <RefreshCw size={14} color={ORANGE} className={refreshing ? "spin-icon" : ""} />
          <span style={{ color: "#eee", fontWeight: 700, fontSize: 12.5 }}>Actualizar</span>
        </button>
      </div>

      <div style={{ display: "flex", gap: 8, marginBottom: 16 }}>
        <TabButton active={tab === "pendientes"} onClick={() => setTab("pendientes")} label="Por entregar" count={pendientes.length} countColor="#f87171" />
        <TabButton active={tab === "entregados"} onClick={() => setTab("entregados")} label="Entregados" count={entregados.length} countColor="#4ade80" />
        <button
          onClick={() => setTab("todos")}
          style={{
            background: tab === "todos" ? "#1a1a1a" : "#141414",
            border: tab === "todos" ? `1.5px solid ${ORANGE}66` : "1px solid #222",
            borderRadius: 12,
            padding: "12px 14px",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            flexShrink: 0,
          }}
        >
          <ClipboardList size={17} color={tab === "todos" ? ORANGE : "#888"} />
        </button>
      </div>

      {listado.length === 0 && (
        <div style={{ color: "#666", textAlign: "center", padding: "30px 0", fontSize: 15 }}>
          {tab === "entregados" ? "Todavía no has entregado ningún domicilio hoy." : "No hay domicilios pendientes ahora mismo."}
        </div>
      )}

      {listado.map((p, idx) => {
        const entregado = p.estadoEntrega === "entregado";
        const metodo = p.metodoPago || "efectivo";
        const metodoColor = metodo === "tarjeta" ? "#60a5fa" : metodo === "brebe" ? "#a78bfa" : "#4ade80";
        const esEfectivo = metodo === "efectivo" || !p.metodoPago;
        return (
          <div key={p.id} style={{ display: "flex", background: entregado ? "#141414" : "#241414", border: `1px solid ${entregado ? "#2f6b46" : "#7a3030"}`, borderRadius: 16, marginBottom: 14, overflow: "hidden" }}>
            {tab === "pendientes" && (
              <div style={{ width: 40, background: "#7a1f1f", display: "flex", alignItems: "center", justifyContent: "center", fontWeight: 900, fontSize: 18, color: "#fff", flexShrink: 0 }}>
                {idx + 1}
              </div>
            )}
            <div style={{ flex: 1, padding: 16, minWidth: 0 }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
                <span style={{ fontWeight: 800, fontSize: 17, textDecoration: entregado ? "line-through" : "none", color: entregado ? "#aaa" : "#fff" }}>Pedido #{p.numero}</span>
                <span style={{ display: "flex", alignItems: "center", gap: 4, color: "#999", fontSize: 12.5 }}>
                  <Clock size={12} /> {new Date(p.timestamp).toLocaleTimeString("es-CO", { hour: "numeric", minute: "2-digit", hour12: true }).toLowerCase()}
                </span>
              </div>

              <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginBottom: 12 }}>
                {!entregado && (
                  <span
                    style={{
                      display: "inline-flex", alignItems: "center", gap: 5,
                      background: p.estadoCocina === "preparado" ? "#12241a" : "#2a1f10",
                      color: p.estadoCocina === "preparado" ? "#4ade80" : "#f5a524",
                      fontSize: 11.5, fontWeight: 700, borderRadius: 999, padding: "4px 10px",
                    }}
                  >
                    {p.estadoCocina === "preparado" ? "✅ Ya está preparado" : "⏳ Aún en cocina"}
                  </span>
                )}
                <span style={{ display: "inline-flex", alignItems: "center", gap: 5, background: "rgba(255,255,255,0.06)", color: metodoColor, fontSize: 11.5, fontWeight: 700, borderRadius: 999, padding: "4px 10px" }}>
                  {metodoPagoLabel(metodo)}
                </span>
              </div>

              {p.items.map((it, i) => (
                <div key={i} style={{ display: "flex", alignItems: "flex-start", gap: 10, padding: "8px 0", borderTop: i > 0 ? "1px solid rgba(255,255,255,0.06)" : "none" }}>
                  <div style={{ background: "#7a1f1f", color: "#fff", fontWeight: 800, fontSize: 12.5, borderRadius: 6, padding: "2px 7px", flexShrink: 0 }}>{it.qty}x</div>
                  <div>
                    <div style={{ fontSize: 15, fontWeight: 700, color: entregado ? "#ccc" : "#fff" }}>{it.name}</div>
                    {it.sin && it.sin.length > 0 && (
                      <div style={{ color: "#f5a524", fontSize: 12, fontWeight: 700, marginTop: 2 }}>⚠️ {it.sin.join(", ")}</div>
                    )}
                  </div>
                </div>
              ))}

              {entregado ? (
                <>
                  <div style={{ color: "#4ade80", fontSize: 12, fontWeight: 700, marginTop: 8 }}>
                    Entregado {p.deliveredAt ? new Date(p.deliveredAt).toLocaleTimeString("es-CO", { hour: "2-digit", minute: "2-digit" }) : ""}
                  </div>
                  <button onClick={() => deshacer(p.id)} style={{ background: "none", border: "none", color: "#888", fontSize: 12, marginTop: 6, textDecoration: "underline", padding: 0 }}>
                    Deshacer entrega
                  </button>
                </>
              ) : (
                <div style={{ display: "flex", alignItems: "center", gap: 10, marginTop: 12 }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 8, flexShrink: 0 }}>
                    <div style={{ width: 32, height: 32, borderRadius: 9, background: "rgba(248,113,113,0.15)", display: "flex", alignItems: "center", justifyContent: "center" }}>
                      <Banknote size={15} color="#f87171" />
                    </div>
                    <div>
                      <div style={{ color: "#999", fontSize: 10.5 }}>Total del pedido</div>
                      <div style={{ color: "#fff", fontWeight: 800, fontSize: 16 }}>{money(p.total)}</div>
                    </div>
                  </div>
                  <button
                    onClick={() => marcarEntregado(p.id)}
                    style={{ flex: 1, background: "#22c55e", border: "none", borderRadius: 12, padding: "13px", color: "#fff", fontWeight: 800, fontSize: 13.5, display: "flex", alignItems: "center", justifyContent: "center", gap: 6 }}
                  >
                    <Check size={17} /> Marcar como entregado
                  </button>
                </div>
              )}

              {esEfectivo && (
                <div
                  style={{
                    background: p.dineroEntregado ? "#12241a" : "#241a10",
                    border: `1px solid ${p.dineroEntregado ? "#2f6b46" : "#7a5a20"}`,
                    borderRadius: 10,
                    padding: "9px 12px",
                    marginTop: 10,
                    textAlign: "center",
                  }}
                >
                  <span style={{ color: p.dineroEntregado ? "#4ade80" : "#f5a524", fontWeight: 700, fontSize: 12.5 }}>
                    {p.dineroEntregado ? "💵 Dinero entregado" : "💵 Dinero pendiente de entregar a caja"}
                  </span>
                </div>
              )}
            </div>
          </div>
        );
      })}
    </div>
  );
}

function TabButton({ active, onClick, label, count, countColor }) {
  return (
    <button
      onClick={onClick}
      style={{
        flex: 1,
        background: active ? "#1a1a1a" : "#141414",
        border: active ? `1.5px solid ${ORANGE}66` : "1px solid #222",
        borderRadius: 12,
        padding: "12px 10px",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        gap: 7,
      }}
    >
      <span style={{ color: active ? ORANGE : "#aaa", fontWeight: 700, fontSize: 13.5 }}>{label}</span>
      <span style={{ background: countColor, color: "#0a0a0a", fontWeight: 800, fontSize: 11.5, borderRadius: 999, minWidth: 19, height: 19, display: "flex", alignItems: "center", justifyContent: "center", padding: "0 5px" }}>
        {count}
      </span>
    </button>
  );
}

function VentasHoyView({ sales, account, pedidos, savePedidos, products, saveProducts, saveSales, role }) {
  const [viewingTicket, setViewingTicket] = useState(null);
  const [editingSale, setEditingSale] = useState(null);
  const [voidConfirmId, setVoidConfirmId] = useState(null);
  const isAdmin = role === "admin";
  const today = todayKey();
  const todays = sales.filter((s) => s.dateKey === today);
  const total = todays.filter((s) => !s.voided).reduce((sum, s) => sum + s.total, 0);

  function pedidoFor(saleId) {
    return (pedidos || []).find((p) => p.saleId === saleId);
  }

  async function confirmarDinero(pedidoId) {
    const next = (pedidos || []).map((p) => (p.id === pedidoId ? { ...p, dineroEntregado: true, dineroEntregadoAt: new Date().toISOString() } : p));
    await savePedidos(next);
  }

  async function anularVenta(sale) {
    const qtyByProduct = {};
    sale.items.forEach((it) => {
      qtyByProduct[it.productId] = (qtyByProduct[it.productId] || 0) + it.qty;
    });
    const updatedProducts = products.map((p) => {
      const qty = qtyByProduct[p.id];
      if (!qty || p.stock == null) return p;
      return { ...p, stock: p.stock + qty };
    });
    await saveProducts(updatedProducts);

    const nextSales = sales.map((s) => (s.id === sale.id ? { ...s, voided: true } : s));
    await saveSales(nextSales);

    const nextPedidos = (pedidos || []).filter((p) => p.saleId !== sale.id);
    await savePedidos(nextPedidos);

    setVoidConfirmId(null);
  }

  async function guardarEdicion(sale, nextItems, nextTotal) {
    const oldQtyByProduct = {};
    sale.items.forEach((it) => {
      oldQtyByProduct[it.productId] = (oldQtyByProduct[it.productId] || 0) + it.qty;
    });
    const newQtyByProduct = {};
    nextItems.forEach((it) => {
      newQtyByProduct[it.productId] = (newQtyByProduct[it.productId] || 0) + it.qty;
    });
    const allIds = new Set([...Object.keys(oldQtyByProduct), ...Object.keys(newQtyByProduct)]);
    const updatedProducts = products.map((p) => {
      if (!allIds.has(p.id) || p.stock == null) return p;
      const diff = (oldQtyByProduct[p.id] || 0) - (newQtyByProduct[p.id] || 0);
      return { ...p, stock: Math.max(0, p.stock + diff) };
    });
    await saveProducts(updatedProducts);

    const nextSales = sales.map((s) => (s.id === sale.id ? { ...s, items: nextItems, total: nextTotal } : s));
    await saveSales(nextSales);

    const nextPedidos = (pedidos || []).map((p) => (p.saleId === sale.id ? { ...p, items: nextItems, total: nextTotal } : p));
    await savePedidos(nextPedidos);

    setEditingSale(null);
  }

  if (viewingTicket) {
    return <TicketView sale={viewingTicket} account={account} onBack={() => setViewingTicket(null)} />;
  }

  if (editingSale) {
    return (
      <EditSaleView
        sale={editingSale}
        onCancel={() => setEditingSale(null)}
        onSave={(nextItems, nextTotal) => guardarEdicion(editingSale, nextItems, nextTotal)}
      />
    );
  }

  return (
    <div style={{ padding: "16px 18px" }}>
      <h2 style={{ margin: "0 0 4px", fontSize: 20 }}>Ventas de hoy</h2>
      <div style={{ color: "#999", fontSize: 14, marginBottom: 18 }}>{todays.length} venta{todays.length !== 1 ? "s" : ""} · {money(total)} en total</div>

      {todays.length === 0 && <div style={{ color: "#666", textAlign: "center", padding: "40px 0", fontSize: 15 }}>Aún no hay ventas registradas hoy.</div>}

      {todays.map((s) => {
        const ped = pedidoFor(s.id);
        const confirmingVoid = voidConfirmId === s.id;
        return (
        <div key={s.id} style={{ background: "#141414", borderRadius: 14, padding: 16, marginBottom: 12, opacity: s.voided ? 0.55 : 1 }}>
          <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 8 }}>
            <span style={{ color: "#999", fontSize: 13 }}>
              {new Date(s.timestamp).toLocaleTimeString("es-CO", { hour: "2-digit", minute: "2-digit" })}
              {s.domicilio && <span style={{ color: ORANGE, fontWeight: 700 }}> · 🛵 Domicilio</span>}
              {s.metodoPago && <span style={{ color: "#999" }}> · {metodoPagoLabel(s.metodoPago)}</span>}
            </span>
            <span style={{ color: s.voided ? "#888" : ORANGE, fontWeight: 700, fontSize: 15, textDecoration: s.voided ? "line-through" : "none" }}>{money(s.total)}</span>
          </div>

          {s.voided && (
            <div style={{ display: "inline-block", background: "#3a1a1a", color: "#f87171", fontSize: 11.5, fontWeight: 800, borderRadius: 6, padding: "4px 8px", marginBottom: 10 }}>
              ANULADA
            </div>
          )}

          {!s.voided && ped && (
            <div style={{ display: "flex", gap: 6, flexWrap: "wrap", marginBottom: 10 }}>
              <span
                style={{
                  fontSize: 11.5,
                  fontWeight: 700,
                  borderRadius: 6,
                  padding: "4px 8px",
                  background: ped.estadoCocina === "preparado" ? "#12241a" : "#2a1f10",
                  color: ped.estadoCocina === "preparado" ? "#4ade80" : "#f5a524",
                }}
              >
                🍳 {ped.estadoCocina === "preparado" ? "Preparado" : "En cocina"}
              </span>
              {ped.domicilio && (
                <span
                  style={{
                    fontSize: 11.5,
                    fontWeight: 700,
                    borderRadius: 6,
                    padding: "4px 8px",
                    background: ped.estadoEntrega === "entregado" ? "#12241a" : "#2a1f10",
                    color: ped.estadoEntrega === "entregado" ? "#4ade80" : "#f5a524",
                  }}
                >
                  🛵 {ped.estadoEntrega === "entregado" ? "Entregado" : "Pendiente de entrega"}
                </span>
              )}
              {ped.domicilio && ped.dineroEntregado && (
                <span style={{ fontSize: 11.5, fontWeight: 700, borderRadius: 6, padding: "4px 8px", background: "#12241a", color: "#4ade80" }}>
                  💵 Dinero entregado
                </span>
              )}
            </div>
          )}

          {!s.voided && ped && ped.domicilio && !ped.dineroEntregado && (
            <button
              onClick={() => confirmarDinero(ped.id)}
              style={{ width: "100%", marginBottom: 10, background: "#1e3a8a", border: "none", borderRadius: 10, padding: "12px", color: "#fff", fontWeight: 700, fontSize: 13.5, display: "flex", alignItems: "center", justifyContent: "center", gap: 7 }}
            >
              💵 Confirmar dinero recibido ({money(s.total)})
            </button>
          )}

          {s.items.map((it, i) => (
            <div key={i} style={{ padding: "3px 0" }}>
              <div style={{ display: "flex", justifyContent: "space-between", fontSize: 14, color: "#ccc" }}>
                <span>{it.qty}x {it.name}</span>
                <span>{money(it.qty * it.price)}</span>
              </div>
              {it.sin && it.sin.length > 0 && <div style={{ color: "#f5a524", fontSize: 12 }}>⚠️ {it.sin.join(", ")}</div>}
            </div>
          ))}
          <button
            onClick={() => setViewingTicket(s)}
            style={{ width: "100%", marginTop: 10, background: "#1a1a1a", border: "1px solid #333", borderRadius: 10, padding: "10px", color: "#ccc", fontWeight: 700, fontSize: 13, display: "flex", alignItems: "center", justifyContent: "center", gap: 7 }}
          >
            <ClipboardList size={15} color={ORANGE} /> Ver ticket
          </button>

          {isAdmin && !s.voided && (
            <div style={{ display: "flex", gap: 8, marginTop: 8 }}>
              <button
                onClick={() => setEditingSale(s)}
                style={{ flex: 1, background: "#1a1a1a", border: "1px solid #333", borderRadius: 10, padding: "10px", color: "#ccc", fontWeight: 700, fontSize: 13, display: "flex", alignItems: "center", justifyContent: "center", gap: 6 }}
              >
                <Pencil size={14} /> Editar orden
              </button>
              {confirmingVoid ? (
                <>
                  <button
                    onClick={() => anularVenta(s)}
                    style={{ flex: 1, background: "#7a3030", border: "none", borderRadius: 10, padding: "10px", color: "#fff", fontWeight: 700, fontSize: 13 }}
                  >
                    Sí, anular
                  </button>
                  <button
                    onClick={() => setVoidConfirmId(null)}
                    style={{ flex: 1, background: "#1a1a1a", border: "1px solid #333", borderRadius: 10, padding: "10px", color: "#999", fontWeight: 700, fontSize: 13 }}
                  >
                    Cancelar
                  </button>
                </>
              ) : (
                <button
                  onClick={() => setVoidConfirmId(s.id)}
                  style={{ flex: 1, background: "#3a1a1a", border: "1px solid #7a3030", borderRadius: 10, padding: "10px", color: "#f87171", fontWeight: 700, fontSize: 13, display: "flex", alignItems: "center", justifyContent: "center", gap: 6 }}
                >
                  <X size={14} /> Anular venta
                </button>
              )}
            </div>
          )}
        </div>
        );
      })}
    </div>
  );
}

function EditSaleView({ sale, onCancel, onSave }) {
  const [items, setItems] = useState(sale.items.map((it) => ({ ...it })));
  const [error, setError] = useState("");

  function bump(idx, delta) {
    setItems((prev) => prev.map((it, i) => (i === idx ? { ...it, qty: Math.max(0, it.qty + delta) } : it)));
  }

  const total = items.reduce((s, it) => s + it.qty * it.price, 0);

  function guardar() {
    const filtered = items.filter((it) => it.qty > 0);
    if (filtered.length === 0) {
      setError('Si quieres dejar la orden en 0, usa "Anular venta" en vez de editarla.');
      return;
    }
    onSave(filtered, total);
  }

  return (
    <div style={{ padding: "16px 18px" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 18 }}>
        <button onClick={onCancel} style={{ background: "#1a1a1a", border: "none", borderRadius: 10, width: 40, height: 40, color: "#fff", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
          <ChevronLeft size={24} />
        </button>
        <h2 style={{ margin: 0, fontSize: 19 }}>Editar orden</h2>
      </div>

      {error && <div style={{ color: "#f87171", fontSize: 14, marginBottom: 14 }}>{error}</div>}

      {items.map((it, idx) => (
        <div key={idx} style={{ background: "#141414", borderRadius: 14, padding: 14, marginBottom: 10, display: "flex", alignItems: "center", gap: 12 }}>
          <div style={{ flex: 1 }}>
            <div style={{ fontWeight: 700, fontSize: 15 }}>{it.name}</div>
            <div style={{ color: "#999", fontSize: 13 }}>{money(it.price)} c/u</div>
            {it.sin && it.sin.length > 0 && <div style={{ color: "#f5a524", fontSize: 11.5 }}>Sin: {it.sin.join(", ")}</div>}
          </div>
          <button onClick={() => bump(idx, -1)} style={{ width: 36, height: 36, borderRadius: 9, border: "none", background: "#2a2a2a", color: "#fff", fontSize: 18, fontWeight: 800 }}>
            −
          </button>
          <div style={{ minWidth: 24, textAlign: "center", fontWeight: 800, fontSize: 16 }}>{it.qty}</div>
          <button onClick={() => bump(idx, 1)} style={{ width: 36, height: 36, borderRadius: 9, border: "none", background: ORANGE, color: "#fff", fontSize: 18, fontWeight: 800 }}>
            +
          </button>
        </div>
      ))}

      <div style={{ background: "#141414", borderRadius: 14, padding: 16, marginTop: 10, marginBottom: 16, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        <span style={{ color: "#999", fontWeight: 700 }}>Nuevo total</span>
        <span style={{ color: ORANGE, fontWeight: 800, fontSize: 18 }}>{money(total)}</span>
      </div>

      <button
        onClick={guardar}
        style={{ width: "100%", background: ORANGE, border: "none", borderRadius: 14, padding: "16px", color: "#fff", fontWeight: 800, fontSize: 16, display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}
      >
        <Check size={18} /> Guardar cambios
      </button>
    </div>
  );
}

// ===== Impresión térmica por Bluetooth (Web Bluetooth API) =====
// Solo funciona en Chrome/Edge para Android. iPhone/Safari no soportan
// Web Bluetooth (restricción de Apple), así que ahí no es posible imprimir.
let btDevice = null;
let btCharacteristic = null;

function padLine(left, right, width) {
  left = String(left);
  right = String(right);
  const spaces = Math.max(1, width - left.length - right.length);
  return left + " ".repeat(spaces) + right;
}

function buildTicketText(sale, account) {
  const width = 32;
  const dateObj = new Date(sale.timestamp);
  const dateLabel = dateObj.toLocaleDateString("es-CO", { day: "2-digit", month: "2-digit", year: "numeric" });
  const timeLabel = dateObj.toLocaleTimeString("es-CO", { hour: "2-digit", minute: "2-digit" });
  const folio = sale.id.replace(/\D/g, "").slice(-6) || sale.id.slice(-6);
  const businessName = (account?.businessName || "Chefwillys").toUpperCase();
  const center = (s) => {
    s = String(s);
    const pad = Math.max(0, Math.floor((width - s.length) / 2));
    return " ".repeat(pad) + s;
  };
  const divider = "-".repeat(width);
  const lines = [];
  lines.push(center(businessName));
  lines.push(center("PUNTO DE VENTA"));
  lines.push(divider);
  lines.push(padLine("Fecha", dateLabel, width));
  lines.push(padLine("Hora", timeLabel, width));
  lines.push(padLine("Ticket No.", "#" + folio, width));
  lines.push(padLine("Tipo", sale.domicilio ? "Domicilio" : "En el local", width));
  if (sale.metodoPago) lines.push(padLine("Pago", metodoPagoLabel(sale.metodoPago).replace(/^\S+\s/, ""), width));
  lines.push(divider);
  sale.items.forEach((it) => {
    lines.push(it.name);
    lines.push(padLine(`${it.qty} x ${money(it.price)}`, money(it.qty * it.price), width));
    if (it.sin && it.sin.length > 0) lines.push("Sin: " + it.sin.join(", "));
  });
  lines.push(divider);
  lines.push(padLine("TOTAL", money(sale.total), width));
  lines.push("");
  lines.push(center("Gracias por su compra"));
  lines.push("");
  lines.push("");
  return lines.join("\n");
}

function textToEscPosBytes(text) {
  const encoder = new TextEncoder();
  const init = new Uint8Array([0x1b, 0x40]); // ESC @ (inicializar impresora)
  const body = encoder.encode(text);
  const feed = new Uint8Array([0x0a, 0x0a, 0x0a]);
  const cut = new Uint8Array([0x1d, 0x56, 0x00]); // GS V 0 (corte, si la impresora lo soporta)
  const combined = new Uint8Array(init.length + body.length + feed.length + cut.length);
  combined.set(init, 0);
  combined.set(body, init.length);
  combined.set(feed, init.length + body.length);
  combined.set(cut, init.length + body.length + feed.length);
  return combined;
}

async function writeInChunks(characteristic, bytes) {
  const chunkSize = 20; // tamaño seguro para la mayoría de impresoras BLE
  for (let i = 0; i < bytes.length; i += chunkSize) {
    const chunk = bytes.slice(i, i + chunkSize);
    await characteristic.writeValue(chunk);
    await new Promise((r) => setTimeout(r, 30));
  }
}

async function getPrinterCharacteristic(serviceUUID, charUUID) {
  if (btCharacteristic && btDevice && btDevice.gatt.connected) {
    return btCharacteristic;
  }
  if (!navigator.bluetooth) {
    throw new Error("Este navegador no soporta impresión por Bluetooth. En iPhone no es posible (restricción de Apple); usa Chrome en Android.");
  }
  btDevice = await navigator.bluetooth.requestDevice({
    acceptAllDevices: true,
    optionalServices: [serviceUUID],
  });
  const server = await btDevice.gatt.connect();
  const service = await server.getPrimaryService(serviceUUID);
  const characteristic = await service.getCharacteristic(charUUID);
  btCharacteristic = characteristic;
  return characteristic;
}

async function printTicketBluetooth(sale, account) {
  const serviceUUID = account?.printerServiceUUID || "000018f0-0000-1000-8000-00805f9b34fb";
  const charUUID = account?.printerCharUUID || "00002af1-0000-1000-8000-00805f9b34fb";
  const characteristic = await getPrinterCharacteristic(serviceUUID, charUUID);
  const text = buildTicketText(sale, account);
  const bytes = textToEscPosBytes(text);
  await writeInChunks(characteristic, bytes);
}

function TicketView({ sale, account, onBack }) {
  const dateObj = new Date(sale.timestamp);
  const dateLabel = dateObj.toLocaleDateString("es-CO", { day: "2-digit", month: "2-digit", year: "numeric" });
  const timeLabel = dateObj.toLocaleTimeString("es-CO", { hour: "2-digit", minute: "2-digit" });
  const folio = sale.id.replace(/\D/g, "").slice(-6) || sale.id.slice(-6);
  const [printStatus, setPrintStatus] = useState(""); // "" | "printing" | "ok" | error message

  function handleDownload() {
    window.print();
  }

  async function handleBluetoothPrint() {
    setPrintStatus("printing");
    try {
      await printTicketBluetooth(sale, account);
      setPrintStatus("ok");
    } catch (err) {
      setPrintStatus(err.message || "No se pudo imprimir.");
    }
  }

  return (
    <div style={{ padding: "16px 18px" }}>
      <style>{`
        @media print {
          body * { visibility: hidden; }
          #ticket-print, #ticket-print * { visibility: visible; }
          #ticket-print {
            position: absolute;
            left: 0;
            top: 0;
            width: 100%;
            background: #fff !important;
            color: #000 !important;
          }
          #ticket-no-print { display: none !important; }
        }
      `}</style>

      <div id="ticket-no-print" style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 16 }}>
        <button onClick={onBack} style={{ background: "#1a1a1a", border: "none", borderRadius: 10, width: 40, height: 40, color: "#fff", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
          <ChevronLeft size={24} />
        </button>
        <h2 style={{ margin: 0, fontSize: 19 }}>Ticket de venta</h2>
      </div>

      <div
        id="ticket-print"
        style={{
          background: "#fff",
          color: "#111",
          borderRadius: 12,
          padding: "24px 20px",
          maxWidth: 340,
          margin: "0 auto",
          fontFamily: "'Courier New', monospace",
        }}
      >
        <div style={{ textAlign: "center", marginBottom: 14 }}>
          {account?.logo && (
            <img src={account.logo} alt={account.businessName} style={{ width: 56, height: 56, borderRadius: 12, objectFit: "cover", margin: "0 auto 8px" }} />
          )}
          <div style={{ fontWeight: 800, fontSize: 17 }}>{account?.businessName || "Chefwillys"}</div>
          <div style={{ fontSize: 11, color: "#555", marginTop: 2 }}>PUNTO DE VENTA</div>
        </div>

        <div style={{ borderTop: "1px dashed #999", borderBottom: "1px dashed #999", padding: "10px 0", marginBottom: 12, fontSize: 12.5 }}>
          <div style={{ display: "flex", justifyContent: "space-between" }}>
            <span>Fecha</span>
            <span>{dateLabel}</span>
          </div>
          <div style={{ display: "flex", justifyContent: "space-between" }}>
            <span>Hora</span>
            <span>{timeLabel}</span>
          </div>
          <div style={{ display: "flex", justifyContent: "space-between" }}>
            <span>Ticket No.</span>
            <span>#{folio}</span>
          </div>
          <div style={{ display: "flex", justifyContent: "space-between" }}>
            <span>Tipo</span>
            <span>{sale.domicilio ? "🛵 Domicilio" : "🏪 En el local"}</span>
          </div>
          {sale.metodoPago && (
            <div style={{ display: "flex", justifyContent: "space-between" }}>
              <span>Pago</span>
              <span>{metodoPagoLabel(sale.metodoPago)}</span>
            </div>
          )}
        </div>

        <div style={{ marginBottom: 12 }}>
          {sale.items.map((it, i) => (
            <div key={i} style={{ marginBottom: 6 }}>
              <div style={{ display: "flex", justifyContent: "space-between", fontSize: 13.5, fontWeight: 700 }}>
                <span>{it.name}</span>
                <span>{money(it.qty * it.price)}</span>
              </div>
              <div style={{ fontSize: 12, color: "#555" }}>{it.qty} x {money(it.price)}</div>
              {it.sin && it.sin.length > 0 && <div style={{ fontSize: 11.5, color: "#b45309" }}>Sin: {it.sin.join(", ")}</div>}
            </div>
          ))}
        </div>

        <div style={{ borderTop: "1px dashed #999", paddingTop: 10, display: "flex", justifyContent: "space-between", fontSize: 16, fontWeight: 800 }}>
          <span>TOTAL</span>
          <span>{money(sale.total)}</span>
        </div>

        <div style={{ textAlign: "center", marginTop: 18, fontSize: 12, color: "#555" }}>
          ¡Gracias por su compra!
        </div>
      </div>

      <button
        id="ticket-no-print"
        onClick={handleBluetoothPrint}
        disabled={printStatus === "printing"}
        style={{ background: "#1e3a8a", width: "100%", maxWidth: 340, margin: "16px auto 0", display: "flex", alignItems: "center", justifyContent: "center", gap: 8, border: "none", borderRadius: 14, padding: "16px", color: "#fff", fontWeight: 700, fontSize: 15 }}
      >
        🖨️ {printStatus === "printing" ? "Conectando con la impresora..." : "Imprimir por Bluetooth"}
      </button>
      {printStatus === "ok" && (
        <div style={{ color: "#4ade80", fontSize: 13, textAlign: "center", marginTop: 8, maxWidth: 340, marginLeft: "auto", marginRight: "auto" }}>
          ✓ Ticket enviado a la impresora.
        </div>
      )}
      {printStatus && printStatus !== "ok" && printStatus !== "printing" && (
        <div style={{ color: "#f87171", fontSize: 13, textAlign: "center", marginTop: 8, maxWidth: 340, marginLeft: "auto", marginRight: "auto" }}>
          {printStatus}
        </div>
      )}

      <button
        id="ticket-no-print"
        onClick={handleDownload}
        style={{ ...primaryBtn, width: "100%", maxWidth: 340, margin: "10px auto 0", display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}
      >
        <Upload size={16} style={{ transform: "rotate(180deg)" }} /> Descargar como PDF
      </button>
      <div id="ticket-no-print" style={{ color: "#888", fontSize: 12, textAlign: "center", marginTop: 8, maxWidth: 340, marginLeft: "auto", marginRight: "auto" }}>
        Se abrirá el diálogo de impresión: elige "Guardar como PDF" para descargarlo.
      </div>
    </div>
  );
}

