function AccesibilidadView({ textSize, setTextSize, onBack }) {
  const options = [
    { key: "small", label: "Pequeño" },
    { key: "normal", label: "Normal" },
    { key: "large", label: "Grande" },
  ];
  return (
    <div style={{ padding: "16px 18px" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 20 }}>
        <button onClick={onBack} style={{ background: "none", border: "none", color: "#fff" }}><ChevronLeft size={22} /></button>
        <h2 style={{ margin: 0 }}>♿ Accesibilidad</h2>
      </div>

      <div style={{ fontWeight: 700, fontSize: 15, marginBottom: 6 }}>Tamaño del texto</div>
      <div style={{ color: "#999", fontSize: 13, marginBottom: 14 }}>
        Cambia el tamaño de la letra en toda la aplicación: productos, categorías, botones, totales, menús, configuración, caja, ventas e inventario.
      </div>

      <div style={{ display: "flex", gap: 8 }}>
        {options.map((o) => (
          <button
            key={o.key}
            onClick={() => setTextSize(o.key)}
            style={{
              flex: 1,
              padding: "16px 0",
              borderRadius: 12,
              border: "none",
              background: textSize === o.key ? ORANGE : "#1a1a1a",
              color: textSize === o.key ? "#fff" : "#999",
              fontWeight: 700,
              fontSize: o.key === "small" ? 13 : o.key === "large" ? 17 : 15,
            }}
          >
            {o.label}
          </button>
        ))}
      </div>
    </div>
  );
}

function TIcon({ name, size = 13, color = "currentColor", strokeWidth = 2 }) {
  const props = { width: size, height: size, viewBox: "0 0 24 24", fill: "none", stroke: color, strokeWidth, strokeLinecap: "round", strokeLinejoin: "round" };
  switch (name) {
    case "share-ios": // ícono de Compartir de iOS: caja con flecha hacia arriba
      return (
        <svg {...props}>
          <path d="M12 3v12" />
          <path d="M8 7l4-4 4 4" />
          <path d="M5 12v7a2 2 0 002 2h10a2 2 0 002-2v-7" />
        </svg>
      );
    case "add-square": // "Agregar a inicio": cuadrado redondeado con +
      return (
        <svg {...props}>
          <rect x="3" y="3" width="18" height="18" rx="5" />
          <path d="M12 8v8M8 12h8" />
        </svg>
      );
    case "star":
      return (
        <svg {...props}>
          <path d="M12 2.8l2.7 5.8 6.3.6-4.8 4.2 1.5 6.2-5.7-3.4-5.7 3.4 1.5-6.2-4.8-4.2 6.3-.6z" />
        </svg>
      );
    case "book":
      return (
        <svg {...props}>
          <path d="M12 6.5c-1.8-1.4-4-2-7-2v13c3 0 5.2.6 7 2 1.8-1.4 4-2 7-2v-13c-3 0-5.2.6-7 2z" />
        </svg>
      );
    case "copy":
      return (
        <svg {...props}>
          <rect x="9" y="9" width="11" height="11" rx="2" />
          <path d="M5 15V5a2 2 0 012-2h10" />
        </svg>
      );
    case "more-vertical":
      return (
        <svg {...props} fill={color} stroke="none">
          <circle cx="12" cy="5.5" r="1.6" />
          <circle cx="12" cy="12" r="1.6" />
          <circle cx="12" cy="18.5" r="1.6" />
        </svg>
      );
    case "plus-tab":
      return (
        <svg {...props}>
          <rect x="4" y="4" width="16" height="16" rx="3" />
          <path d="M12 8v8M8 12h8" />
        </svg>
      );
    case "incognito":
      return (
        <svg {...props}>
          <path d="M4 12.5a8 8 0 0116 0" />
          <circle cx="8.2" cy="14.5" r="2" />
          <circle cx="15.8" cy="14.5" r="2" />
          <path d="M10.2 14.5h3.6" />
        </svg>
      );
    case "history":
      return (
        <svg {...props}>
          <circle cx="12" cy="13" r="8" />
          <path d="M12 9v4l3 2" />
          <path d="M9 2h6" />
        </svg>
      );
    case "download":
      return (
        <svg {...props}>
          <path d="M12 3v11" />
          <path d="M7.5 10.5L12 15l4.5-4.5" />
          <path d="M5 20h14" />
        </svg>
      );
    case "layers":
      return (
        <svg {...props}>
          <path d="M12 3l9 5-9 5-9-5 9-5z" />
          <path d="M3 13l9 5 9-5" />
        </svg>
      );
    case "monitor":
      return (
        <svg {...props}>
          <rect x="2.5" y="4.5" width="19" height="13" rx="2" />
          <path d="M8 20.5h8M12 17.5v3" />
        </svg>
      );
    case "home":
      return (
        <svg {...props}>
          <path d="M4 11.5L12 4l8 7.5" />
          <path d="M6 10v9.5h12V10" />
        </svg>
      );
    case "refresh":
      return (
        <svg {...props}>
          <path d="M4 12a8 8 0 0114-5.3" />
          <path d="M20 3v5h-5" />
          <path d="M20 12a8 8 0 01-14 5.3" />
          <path d="M4 21v-5h5" />
        </svg>
      );
    case "chevron-right":
      return (
        <svg {...props}>
          <path d="M9 5l7 7-7 7" />
        </svg>
      );
    case "signal":
      return (
        <svg {...props} fill={color} stroke="none">
          <rect x="2" y="14" width="3.2" height="7" rx="0.8" />
          <rect x="7.4" y="10.5" width="3.2" height="10.5" rx="0.8" />
          <rect x="12.8" y="7" width="3.2" height="14" rx="0.8" />
          <rect x="18.2" y="3.5" width="3.2" height="17.5" rx="0.8" />
        </svg>
      );
    case "wifi":
      return (
        <svg {...props}>
          <path d="M3 8.5a13 13 0 0118 0" />
          <path d="M6.2 12.3a8.5 8.5 0 0111.6 0" />
          <path d="M9.5 16a4 4 0 015 0" />
          <circle cx="12" cy="19.2" r="1" fill={color} stroke="none" />
        </svg>
      );
    case "battery":
      return (
        <svg {...props} fill="none">
          <rect x="1.5" y="7" width="19" height="10" rx="2.5" stroke={color} />
          <rect x="21.3" y="10" width="1.4" height="4" rx="0.7" fill={color} stroke="none" />
          <rect x="3.3" y="8.8" width="15.4" height="6.4" rx="1.2" fill={color} stroke="none" />
        </svg>
      );
    default:
      return null;
  }
}

