                <div
                  style={{
                    display: "flex",
                    alignItems: "center",
                    justifyContent: "center",
                    gap: 8,
                    padding: "9px 0",
                    background: urgente ? "#c62828" : "#a86a1f",
                    fontWeight: 900,
                    fontSize: 13,
                    letterSpacing: 1,
                  }}
                >
                  {urgente ? <><Flame size={15} /> PRIORIDAD ALTA</> : <><Bell size={15} /> EN ESPERA</>}
                </div>

                <button
