function BusinessForm({ account, onSave, onCancel }) {
  const [username, setUsername] = useState(account?.username || "");
  const [newPassword, setNewPassword] = useState("");
  const [error, setError] = useState("");
  const [saving, setSaving] = useState(false);

  async function submit() {
    if (!username.trim()) {
      setError("El usuario es obligatorio.");
      return;
    }
    if (newPassword.trim() && newPassword.trim().length < 6) {
      setError("La nueva contraseña debe tener al menos 6 caracteres.");
      return;
    }
    setError("");
    setSaving(true);
    if (newPassword.trim()) {
      const { error: pwError } = await supabase.auth.updateUser({ password: newPassword.trim() });
      if (pwError) {
        setError("No se pudo cambiar la contraseña: " + pwError.message);
        setSaving(false);
        return;
      }
    }
    onSave({
      ...account,
      username: username.trim(),
    });
    setSaving(false);
  }

  return (
    <div style={{ padding: "16px 18px" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 16 }}>
        <button onClick={onCancel} style={{ background: "none", border: "none", color: "#fff" }}><ChevronLeft size={22} /></button>
        <h2 style={{ margin: 0 }}>Mi cuenta</h2>
      </div>

      {error && <div style={{ color: "#f87171", fontSize: 13, marginBottom: 12 }}>{error}</div>}

      <Field label="Usuario"><input style={inputStyle} value={username} onChange={(e) => setUsername(e.target.value)} /></Field>
      <Field label="Correo electrónico (para iniciar sesión)">
        <input style={{ ...inputStyle, opacity: 0.6 }} value={account?.email || ""} disabled />
      </Field>
      <Field label="Nueva contraseña (déjalo vacío para no cambiarla)">
        <PasswordInput autoComplete="new-password" value={newPassword} onChange={(e) => setNewPassword(e.target.value)} placeholder="••••••••" />
      </Field>

      <button onClick={submit} disabled={saving} style={{ ...primaryBtn, width: "100%", marginTop: 8, display: "flex", alignItems: "center", justifyContent: "center", gap: 8, opacity: saving ? 0.7 : 1 }}>
        <Check size={16} /> {saving ? "Guardando..." : "Guardar"}
      </button>
    </div>
  );
}

const WORKER_ROLE_META = {
  admin: { icon: "👑", label: "Administrador", bg: "rgba(34,197,94,0.15)" },
  cocina: { icon: "🍳", label: "Cocina", bg: "rgba(245,130,31,0.15)" },
  domiciliario: { icon: "🛵", label: "Domiciliario", bg: "rgba(59,130,246,0.15)" },
  cajero: { icon: "💰", label: "Caja", bg: "rgba(250,204,21,0.15)" },
};

function WorkersManager({ account, saveAccount, onBack, asistencia }) {
  const [editing, setEditing] = useState(null); // null | "new" | worker object
  const [viewingPayroll, setViewingPayroll] = useState(null); // worker object
  const [error, setError] = useState("");
  const workers = account?.workers || [];

  async function handleSave(worker) {
    const isNew = editing === "new";
    const others = workers.filter((w) => (isNew ? true : w.id !== editing.id));
    const usernameTaken = others.some((w) => w.username.trim().toLowerCase() === worker.username.trim().toLowerCase());
    if (usernameTaken) {
      setError("Ya existe un trabajador con ese usuario. Elige otro.");
      return;
    }
    setError("");
    const next = isNew
      ? [...workers, { ...worker, id: Date.now().toString(36) + Math.random().toString(36).slice(2, 6) }]
      : workers.map((w) => (w.id === editing.id ? { ...w, ...worker } : w));
    await saveAccount({ ...account, workers: next });
    setEditing(null);
  }

  async function handleDelete(id) {
    const next = workers.filter((w) => w.id !== id);
    await saveAccount({ ...account, workers: next });
  }

  if (viewingPayroll) {
    return (
      <WorkerPayrollView
        worker={viewingPayroll}
        account={account}
        saveAccount={saveAccount}
        asistencia={asistencia}
        onBack={() => setViewingPayroll(null)}
      />
    );
  }

  if (editing) {
    return (
      <WorkerForm
        worker={editing === "new" ? null : editing}
        onSave={handleSave}
        onCancel={() => {
          setEditing(null);
          setError("");
        }}
        error={error}
      />
    );
  }

  return (
    <div style={{ padding: "16px 18px" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 16 }}>
        <button onClick={onBack} style={{ background: "none", border: "none", color: "#fff" }}><ChevronLeft size={22} /></button>
        <h2 style={{ margin: 0 }}>Trabajadores</h2>
      </div>

      <div style={{ color: "#999", fontSize: 13, marginBottom: 16 }}>
        Crea un usuario y contraseña para cada persona. Con eso entran directo a su puesto (Administrador, Cocina o Domiciliario), sin necesidad de correo.
      </div>

      <button
        onClick={() => setEditing("new")}
        style={{ width: "100%", background: ORANGE, border: "none", borderRadius: 12, padding: "14px", color: "#fff", fontWeight: 800, fontSize: 15, marginBottom: 18, display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}
      >
        <Plus size={18} /> Agregar trabajador
      </button>

      {workers.length === 0 && (
        <div style={{ color: "#666", textAlign: "center", padding: "24px 0", fontSize: 14 }}>Todavía no has agregado trabajadores.</div>
      )}

      {workers.map((w) => {
        const meta = WORKER_ROLE_META[w.role] || WORKER_ROLE_META.cocina;
        return (
          <div key={w.id} style={{ background: "#141414", borderRadius: 14, padding: 14, marginBottom: 10 }}>
            <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 10 }}>
              <div style={{ width: 44, height: 44, borderRadius: w.photo ? "50%" : 12, overflow: "hidden", background: meta.bg, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 20, flexShrink: 0 }}>
                {w.photo ? <img src={w.photo} alt="" style={{ width: "100%", height: "100%", objectFit: "cover" }} /> : meta.icon}
              </div>
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ fontWeight: 700, fontSize: 15 }}>{w.name}</div>
                <div style={{ color: "#999", fontSize: 12.5 }}>@{w.username} · {meta.label}</div>
              </div>
              <button onClick={() => setEditing(w)} style={{ background: "#1a1a1a", border: "none", borderRadius: 9, width: 36, height: 36, color: "#fff", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
                <Pencil size={15} />
              </button>
              <button onClick={() => handleDelete(w.id)} style={{ background: "#1a1a1a", border: "none", borderRadius: 9, width: 36, height: 36, color: "#f87171", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
                <Trash2 size={15} />
              </button>
            </div>
            <button
              onClick={() => setViewingPayroll(w)}
              style={{ width: "100%", background: "#12241a", border: "1px solid #2f6b46", borderRadius: 10, padding: "10px", color: "#4ade80", fontWeight: 700, fontSize: 13, display: "flex", alignItems: "center", justifyContent: "center", gap: 7 }}
            >
              💵 Días trabajados y pagos
            </button>
          </div>
        );
      })}
    </div>
  );
}

function WorkerForm({ worker, onSave, onCancel, error }) {
  const [name, setName] = useState(worker?.name || "");
  const [username, setUsername] = useState(worker?.username || "");
  const [password, setPassword] = useState("");
  const [role, setRole] = useState(worker?.role || "cocina");
  const [photo, setPhoto] = useState(worker?.photo || "");
  const [pagoPorDia, setPagoPorDia] = useState(worker?.pagoPorDia ?? "");
  const [localError, setLocalError] = useState("");

  function submit() {
    if (!name.trim()) {
      setLocalError("El nombre es obligatorio.");
      return;
    }
    if (!username.trim()) {
      setLocalError("El usuario es obligatorio.");
      return;
    }
    if (!worker && !password.trim()) {
      setLocalError("La contraseña es obligatoria.");
      return;
    }
    if (password.trim() && password.trim().length < 4) {
      setLocalError("La contraseña debe tener al menos 4 caracteres.");
      return;
    }
    setLocalError("");
    onSave({
      name: name.trim(),
      username: username.trim(),
      password: password.trim() ? password.trim() : worker.password,
      role,
      photo,
      pagoPorDia: pagoPorDia === "" ? 0 : parseFloat(pagoPorDia),
      pagos: worker?.pagos || [],
    });
  }

  return (
    <div style={{ padding: "16px 18px" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 16 }}>
        <button onClick={onCancel} style={{ background: "none", border: "none", color: "#fff" }}><ChevronLeft size={22} /></button>
        <h2 style={{ margin: 0 }}>{worker ? "Editar trabajador" : "Nuevo trabajador"}</h2>
      </div>

      {(localError || error) && <div style={{ color: "#f87171", fontSize: 13, marginBottom: 12 }}>{localError || error}</div>}

      <div style={{ display: "flex", justifyContent: "center", marginBottom: 18 }}>
        <div style={{ width: 84, height: 84, borderRadius: "50%", overflow: "hidden", background: "#1a1a1a", border: `2px solid ${ORANGE}`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 34 }}>
          {photo ? <img src={photo} alt="" style={{ width: "100%", height: "100%", objectFit: "cover" }} /> : (WORKER_ROLE_META[role]?.icon || "🙂")}
        </div>
      </div>
      <div style={{ marginBottom: 14 }}>
        <PhotoPicker onPick={setPhoto} label={photo ? "Cambiar foto de perfil" : "Agregar foto de perfil"} />
      </div>

      <Field label="Nombre"><input style={inputStyle} value={name} onChange={(e) => setName(e.target.value)} placeholder="Ej: Juan Pérez" /></Field>
      <Field label="Usuario">
        <input autoCapitalize="none" autoCorrect="off" style={inputStyle} value={username} onChange={(e) => setUsername(e.target.value)} placeholder="Ej: juan" />
      </Field>
      <Field label={worker ? "Nueva contraseña (déjalo vacío para no cambiarla)" : "Contraseña"}>
        <PasswordInput autoComplete="new-password" value={password} onChange={(e) => setPassword(e.target.value)} placeholder="••••••••" />
      </Field>
      <Field label="Pago por día trabajado">
        <input
          type="number"
          inputMode="decimal"
          style={inputStyle}
          value={pagoPorDia}
          onChange={(e) => setPagoPorDia(e.target.value)}
          placeholder="Ej: 50000"
        />
      </Field>

      <div style={{ color: "#999", fontSize: 13, margin: "16px 0 10px" }}>Puesto</div>
      <div style={{ display: "flex", gap: 6, marginBottom: 20, flexWrap: "wrap" }}>
        <button
          onClick={() => setRole("admin")}
          style={{ flex: "1 1 45%", padding: "14px 4px", borderRadius: 12, border: "none", background: role === "admin" ? ORANGE : "#1a1a1a", color: role === "admin" ? "#fff" : "#999", fontWeight: 700, fontSize: 13 }}
        >
          👑 Admin
        </button>
        <button
          onClick={() => setRole("cocina")}
          style={{ flex: "1 1 45%", padding: "14px 4px", borderRadius: 12, border: "none", background: role === "cocina" ? ORANGE : "#1a1a1a", color: role === "cocina" ? "#fff" : "#999", fontWeight: 700, fontSize: 13 }}
        >
          🍳 Cocina
        </button>
        <button
          onClick={() => setRole("domiciliario")}
          style={{ flex: "1 1 45%", padding: "14px 4px", borderRadius: 12, border: "none", background: role === "domiciliario" ? ORANGE : "#1a1a1a", color: role === "domiciliario" ? "#fff" : "#999", fontWeight: 700, fontSize: 13 }}
        >
          🛵 Domicilio
        </button>
        <button
          onClick={() => setRole("cajero")}
          style={{ flex: "1 1 45%", padding: "14px 4px", borderRadius: 12, border: "none", background: role === "cajero" ? ORANGE : "#1a1a1a", color: role === "cajero" ? "#fff" : "#999", fontWeight: 700, fontSize: 13 }}
        >
          💰 Caja
        </button>
      </div>
      {role === "admin" && (
        <div style={{ color: "#f5a524", fontSize: 12.5, marginTop: -12, marginBottom: 20 }}>
          ⚠️ Este puesto da acceso completo: ventas, productos, caja, trabajadores y ajustes del negocio.
        </div>
      )}

      <button onClick={submit} style={{ ...primaryBtn, width: "100%", display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}>
        <Check size={16} /> Guardar
      </button>
    </div>
  );
}

function quincenaLabelDays(startDay, endDay) {
  return `${startDay} al ${endDay}`;
}

function WorkerPayrollView({ worker, account, saveAccount, asistencia, onBack }) {
  const [monthOffset, setMonthOffset] = useState(0); // 0 = mes actual, negativo = meses anteriores
  const [pagoPorDiaInput, setPagoPorDiaInput] = useState(String(worker.pagoPorDia ?? 0));
  const [saving, setSaving] = useState(false);
  const [savedMsg, setSavedMsg] = useState("");

  const base = new Date();
  base.setDate(1);
  base.setMonth(base.getMonth() + monthOffset);
  const year = base.getFullYear();
  const month = base.getMonth(); // 0-indexado
  const monthPrefix = `${year}-${String(month + 1).padStart(2, "0")}`;
  const monthLabelRaw = base.toLocaleDateString("es-CO", { month: "long", year: "numeric" });
  const monthLabel = monthLabelRaw.charAt(0).toUpperCase() + monthLabelRaw.slice(1);
  const daysInMonth = new Date(year, month + 1, 0).getDate();

  const diasTrabajadosFechas = Object.entries(asistencia || {})
    .filter(([dateKey, ids]) => dateKey.startsWith(monthPrefix) && (ids || []).includes(worker.id))
    .map(([dateKey]) => dateKey)
    .sort();

  function buildQuincena(startDay, endDay, qNum) {
    const dias = diasTrabajadosFechas.filter((dk) => {
      const d = parseInt(dk.slice(8, 10), 10);
      return d >= startDay && d <= endDay;
    });
    const qKey = `${monthPrefix}-Q${qNum}`;
    const pagoRegistro = (worker.pagos || []).find((p) => p.quincena === qKey);
    const subtotal = dias.length * (worker.pagoPorDia || 0);
    return { qKey, dias, subtotal, pagado: !!pagoRegistro };
  }

  const q1 = buildQuincena(1, 15, 1);
  const q2 = buildQuincena(16, daysInMonth, 2);
  const pendienteTotal = (q1.pagado ? 0 : q1.subtotal) + (q2.pagado ? 0 : q2.subtotal);

  async function guardarPagoPorDia() {
    setSaving(true);
    const val = pagoPorDiaInput === "" ? 0 : parseFloat(pagoPorDiaInput);
    const workers = (account.workers || []).map((w) => (w.id === worker.id ? { ...w, pagoPorDia: val } : w));
    await saveAccount({ ...account, workers });
    worker.pagoPorDia = val; // refleja el cambio de inmediato en esta pantalla
    setSaving(false);
    setSavedMsg("Guardado.");
    setTimeout(() => setSavedMsg(""), 2500);
  }

  async function marcarPagado(q) {
    const nuevoPago = { quincena: q.qKey, amount: q.subtotal, paidAt: new Date().toISOString() };
    const workers = (account.workers || []).map((w) =>
      w.id === worker.id ? { ...w, pagos: [...(w.pagos || []).filter((p) => p.quincena !== q.qKey), nuevoPago] } : w
    );
    await saveAccount({ ...account, workers });
  }

  async function desmarcarPagado(q) {
    const workers = (account.workers || []).map((w) =>
      w.id === worker.id ? { ...w, pagos: (w.pagos || []).filter((p) => p.quincena !== q.qKey) } : w
    );
    await saveAccount({ ...account, workers });
  }

  function QuincenaCard({ label, q }) {
    return (
      <div style={{ background: "#141414", borderRadius: 14, padding: 16, marginBottom: 14 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
          <div style={{ fontWeight: 800, fontSize: 15 }}>{label}</div>
          {q.pagado ? (
            <span style={{ background: "#12241a", color: "#4ade80", fontSize: 11.5, fontWeight: 800, borderRadius: 6, padding: "4px 8px" }}>✓ PAGADO</span>
          ) : (
            <span style={{ background: "#2a1f10", color: "#f5a524", fontSize: 11.5, fontWeight: 800, borderRadius: 6, padding: "4px 8px" }}>PENDIENTE</span>
          )}
        </div>
        <div style={{ color: "#999", fontSize: 13, marginBottom: 10 }}>
          {q.dias.length} día{q.dias.length !== 1 ? "s" : ""} trabajado{q.dias.length !== 1 ? "s" : ""}
        </div>
        {q.dias.length > 0 && (
          <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginBottom: 12 }}>
            {q.dias.map((dk) => (
              <span key={dk} style={{ background: "#1a1a1a", borderRadius: 8, padding: "5px 9px", fontSize: 12.5, fontWeight: 700, color: "#ccc" }}>
                {parseInt(dk.slice(8, 10), 10)}
              </span>
            ))}
          </div>
        )}
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: q.dias.length > 0 ? 12 : 0 }}>
          <span style={{ color: "#999", fontSize: 13, fontWeight: 700 }}>Subtotal</span>
          <span style={{ color: ORANGE, fontWeight: 800, fontSize: 18 }}>{money(q.subtotal)}</span>
        </div>
        {q.dias.length > 0 &&
          (q.pagado ? (
            <button
              onClick={() => desmarcarPagado(q)}
              style={{ width: "100%", background: "#1a1a1a", border: "1px solid #333", borderRadius: 10, padding: "12px", color: "#999", fontWeight: 700, fontSize: 13 }}
            >
              Deshacer pago
            </button>
          ) : (
            <button
              onClick={() => marcarPagado(q)}
              style={{ width: "100%", background: "#22c55e", border: "none", borderRadius: 10, padding: "12px", color: "#fff", fontWeight: 800, fontSize: 14, display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}
            >
              <Check size={16} /> Marcar quincena como pagada
            </button>
          ))}
      </div>
    );
  }

  return (
    <div style={{ padding: "16px 18px" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 16 }}>
        <button onClick={onBack} style={{ background: "none", border: "none", color: "#fff" }}><ChevronLeft size={22} /></button>
        <h2 style={{ margin: 0, fontSize: 19 }}>{worker.name}</h2>
      </div>

      <div style={{ background: "#141414", borderRadius: 14, padding: 16, marginBottom: 16 }}>
        <div style={{ color: "#999", fontSize: 13, marginBottom: 8 }}>Pago por día trabajado</div>
        <div style={{ display: "flex", gap: 8 }}>
          <input
            type="number"
            inputMode="decimal"
            style={{ ...inputStyle, flex: 1 }}
            value={pagoPorDiaInput}
            onChange={(e) => setPagoPorDiaInput(e.target.value)}
          />
          <button
            onClick={guardarPagoPorDia}
            disabled={saving}
            style={{ background: ORANGE, border: "none", borderRadius: 10, padding: "0 18px", color: "#fff", fontWeight: 800, opacity: saving ? 0.7 : 1 }}
          >
            {saving ? "..." : "Guardar"}
          </button>
        </div>
        {savedMsg && <div style={{ color: "#4ade80", fontSize: 12.5, marginTop: 8 }}>{savedMsg}</div>}
      </div>

      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 14 }}>
        <button onClick={() => setMonthOffset((o) => o - 1)} style={{ background: "#1a1a1a", border: "none", borderRadius: 10, width: 40, height: 40, color: "#fff", fontSize: 18 }}>
          ‹
        </button>
        <div style={{ fontWeight: 800, fontSize: 16 }}>{monthLabel}</div>
        <button
          onClick={() => setMonthOffset((o) => Math.min(0, o + 1))}
          disabled={monthOffset === 0}
          style={{ background: "#1a1a1a", border: "none", borderRadius: 10, width: 40, height: 40, color: monthOffset === 0 ? "#444" : "#fff", fontSize: 18 }}
        >
          ›
        </button>
      </div>

      <div style={{ background: "linear-gradient(135deg, #2a1608, #1a0f05)", border: "1px solid rgba(245,130,31,0.3)", borderRadius: 16, padding: 18, marginBottom: 18, textAlign: "center" }}>
        <div style={{ color: "#f0c9a0", fontSize: 12, fontWeight: 700, letterSpacing: 1, marginBottom: 6 }}>PENDIENTE POR PAGAR</div>
        <div style={{ color: ORANGE, fontWeight: 800, fontSize: 28 }}>{money(pendienteTotal)}</div>
      </div>

      <QuincenaCard label={`Quincena 1 (${quincenaLabelDays(1, 15)})`} q={q1} />
      <QuincenaCard label={`Quincena 2 (${quincenaLabelDays(16, daysInMonth)})`} q={q2} />
    </div>
  );
}

function WorkerStatsView({ worker, workerId, role, pedidos, asistencia, account, saveAccount, onBack }) {
  const [photo, setPhoto] = useState(worker?.photo || "");
  const [saving, setSaving] = useState(false);

  async function handlePhotoChange(dataUrl) {
    setPhoto(dataUrl);
    setSaving(true);
    const workers = (account.workers || []).map((w) => (w.id === workerId ? { ...w, photo: dataUrl } : w));
    await saveAccount({ ...account, workers });
    setSaving(false);
  }

  const now = new Date();
  const monthPrefix = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, "0")}`;
  const daysInMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0).getDate();

  const diasTrabajados = Object.entries(asistencia || {}).filter(
    ([dateKey, ids]) => dateKey.startsWith(monthPrefix) && (ids || []).includes(workerId)
  ).length;

  const isCocina = role === "cocina";
  const isDomiciliario = role === "domiciliario";
  const trackaPedidos = isCocina || isDomiciliario;
  const campoResponsable = isCocina ? "preparedByWorkerId" : "deliveredByWorkerId";
  const campoFecha = isCocina ? "preparedAt" : "deliveredAt";

  const misPedidosMes = trackaPedidos
    ? pedidos.filter((p) => p[campoResponsable] === workerId && p[campoFecha] && p[campoFecha].slice(0, 7) === monthPrefix)
    : [];

  const dailyCounts = Array.from({ length: daysInMonth }, (_, i) => {
    const day = i + 1;
    const dateStr = `${monthPrefix}-${String(day).padStart(2, "0")}`;
    return { day, cantidad: misPedidosMes.filter((p) => p.dateKey === dateStr).length };
  });

  const totalMes = misPedidosMes.length;
  const meta = WORKER_ROLE_META[role] || WORKER_ROLE_META.cocina;

  const motivational =
    totalMes === 0
      ? "¡Hoy es un gran día para empezar! 💪"
      : totalMes < 10
      ? "¡Vas muy bien, sigue así! 🔥"
      : totalMes < 30
      ? "¡Excelente ritmo este mes! 🌟"
      : "¡Eres una máquina! 🏆";

  return (
    <div style={{ padding: "16px 18px" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 18 }}>
        <button onClick={onBack} style={{ background: "none", border: "none", color: "#fff" }}><ChevronLeft size={22} /></button>
        <h2 style={{ margin: 0, fontSize: 20 }}>Mi perfil</h2>
      </div>

      <div style={{ display: "flex", flexDirection: "column", alignItems: "center", marginBottom: 22 }}>
        <div style={{ width: 96, height: 96, borderRadius: "50%", overflow: "hidden", background: "#1a1a1a", border: `3px solid ${ORANGE}`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 40, marginBottom: 12 }}>
          {photo ? <img src={photo} alt="" style={{ width: "100%", height: "100%", objectFit: "cover" }} /> : meta.icon}
        </div>
        <div style={{ fontWeight: 800, fontSize: 18 }}>{worker?.name || "Sin nombre"}</div>
        <div style={{ color: "#999", fontSize: 13 }}>{meta.label}</div>
        <div style={{ marginTop: 14, width: "100%", maxWidth: 280 }}>
          <PhotoPicker onPick={handlePhotoChange} label={saving ? "Guardando..." : photo ? "Cambiar foto de perfil" : "Agregar foto de perfil"} />
        </div>
      </div>

      <div style={{ display: "flex", gap: 10, marginBottom: 20 }}>
        <div style={{ flex: 1, background: "#141414", borderRadius: 14, padding: 16, textAlign: "center" }}>
          <div style={{ color: ORANGE, fontWeight: 800, fontSize: 26 }}>{diasTrabajados}</div>
          <div style={{ color: "#999", fontSize: 12 }}>Días trabajados este mes</div>
        </div>
        {trackaPedidos && (
          <div style={{ flex: 1, background: "#141414", borderRadius: 14, padding: 16, textAlign: "center" }}>
            <div style={{ color: "#4ade80", fontWeight: 800, fontSize: 26 }}>{totalMes}</div>
            <div style={{ color: "#999", fontSize: 12 }}>{isCocina ? "Preparados este mes" : "Entregados este mes"}</div>
          </div>
        )}
      </div>

      {trackaPedidos && (
        <>
          <div style={{ background: "linear-gradient(135deg, #ffb347, #f5821f 60%, #c85f0f)", borderRadius: 14, padding: 16, marginBottom: 18, textAlign: "center" }}>
            <div style={{ fontWeight: 800, fontSize: 15, color: "#fff" }}>{motivational}</div>
          </div>

          <div style={{ color: "#999", fontSize: 13, marginBottom: 10 }}>
            {isCocina ? "Pedidos preparados por día" : "Pedidos entregados por día"}
          </div>
          <div style={{ background: "#141414", borderRadius: 14, padding: "12px 8px 4px", marginBottom: 20 }}>
            <ResponsiveContainer width="100%" height={180}>
              <BarChart data={dailyCounts}>
                <XAxis dataKey="day" tick={{ fill: "#666", fontSize: 10 }} axisLine={false} tickLine={false} interval={2} />
                <YAxis hide />
                <Tooltip
                  contentStyle={{ background: "#0a0a0a", border: "1px solid #333", borderRadius: 8, fontSize: 12 }}
                  labelFormatter={(d) => `Día ${d}`}
                  formatter={(v) => [v, isCocina ? "Preparados" : "Entregados"]}
                />
                <Bar dataKey="cantidad" fill={ORANGE} radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </>
      )}
    </div>
  );
}

