function InsumoForm({ insumo, onSave, onCancel }) {
  const [name, setName] = useState(insumo?.name || "");
  const [unit, setUnit] = useState(insumo?.unit || UNITS[0]);
  const [stock, setStock] = useState(insumo?.stock ?? "");
  const [stockMinimo, setStockMinimo] = useState(insumo?.stockMinimo ?? "");
  const [icon, setIcon] = useState(insumo?.icon || "📦");
  const [error, setError] = useState("");

  function submit() {
    if (!name.trim() || stock === "" || isNaN(parseFloat(stock))) {
      setError("El nombre y la cantidad son obligatorios.");
      return;
    }
    onSave({
      name: name.trim(),
      unit,
      stock: parseFloat(stock),
      stockMinimo: stockMinimo === "" ? null : parseFloat(stockMinimo),
      icon: icon.trim() || "📦",
    });
  }

  return (
    <div style={{ padding: "16px 18px" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 20 }}>
        <button onClick={onCancel} style={{ background: "#1a1a1a", border: "none", borderRadius: 10, width: 40, height: 40, color: "#fff", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}><ChevronLeft size={24} /></button>
        <h2 style={{ margin: 0, fontSize: 19 }}>{insumo ? "Editar insumo" : "Nuevo insumo"}</h2>
      </div>

      {error && <div style={{ color: "#f87171", fontSize: 14, marginBottom: 14 }}>{error}</div>}

      <div style={{ display: "flex", justifyContent: "center", marginBottom: 16 }}>
        {isImageSrc(icon) ? (
          <img src={icon} alt="Foto del insumo" style={{ width: 90, height: 90, borderRadius: 18, objectFit: "cover", border: `2px solid ${ORANGE}` }} />
        ) : (
          <div style={{ width: 90, height: 90, borderRadius: 18, background: "#1a1a1a", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 44 }}>
            {icon || "📦"}
          </div>
        )}
      </div>

      <div style={{ marginBottom: 14 }}>
        <PhotoPicker label="Subir foto desde el teléfono" onPick={(dataUrl) => setIcon(dataUrl)} />
      </div>

      <Field label="Nombre del insumo"><input style={bigInputStyle} value={name} onChange={(e) => setName(e.target.value)} placeholder="Ej: Pan para hamburguesa" /></Field>
      <Field label="O escribe un emoji en vez de foto (opcional)">
        <input style={bigInputStyle} value={isImageSrc(icon) ? "" : icon} onChange={(e) => setIcon(e.target.value)} placeholder="🍞" />
      </Field>
      <Field label="Unidad de medida">
        <select style={bigInputStyle} value={unit} onChange={(e) => setUnit(e.target.value)}>
          {UNITS.map((u) => (
            <option key={u} value={u}>{u}</option>
          ))}
        </select>
      </Field>
      <Field label="Cantidad actual en bodega">
        <input type="number" style={bigInputStyle} value={stock} onChange={(e) => setStock(e.target.value)} />
      </Field>
      <Field label="Stock mínimo (avisa cuando quede igual o por debajo)">
        <input type="number" style={bigInputStyle} value={stockMinimo} onChange={(e) => setStockMinimo(e.target.value)} placeholder="Ej: 5" />
      </Field>

      <button onClick={submit} style={{ ...primaryBtn, width: "100%", marginTop: 10, padding: "16px", fontSize: 16, display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}>
        <Check size={18} /> Guardar insumo
      </button>
    </div>
  );
}

function PhotoPicker({ onPick, label }) {
  const inputRef = useRef(null);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  async function handleChange(e) {
    const file = e.target.files && e.target.files[0];
    if (!file) return;
    setLoading(true);
    setError("");
    try {
      const dataUrl = await resizeImageFile(file);
      onPick(dataUrl);
    } catch (err) {
      setError(err.message || "No se pudo cargar la foto.");
    }
    setLoading(false);
    e.target.value = "";
  }

  return (
    <div>
      <button
        type="button"
        onClick={() => inputRef.current && inputRef.current.click()}
        style={{ width: "100%", background: "#1a1a1a", border: `1px solid ${ORANGE}`, borderRadius: 10, padding: "12px", color: ORANGE, fontWeight: 700, fontSize: 14, display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}
      >
        <Upload size={16} /> {loading ? "Cargando..." : (label || "Subir foto desde el teléfono")}
      </button>
      <input ref={inputRef} type="file" accept="image/*" style={{ display: "none" }} onChange={handleChange} />
      {error && <div style={{ color: "#f87171", fontSize: 12, marginTop: 6 }}>{error}</div>}
    </div>
  );
}

function Field({ label, children }) {
  return (
    <div style={{ marginBottom: 14 }}>
      <div style={{ color: "#999", fontSize: 13, marginBottom: 6 }}>{label}</div>
      {children}
    </div>
  );
}

function PasswordInput({ value, onChange, autoComplete, placeholder, style }) {
  const [visible, setVisible] = useState(false);
  return (
    <div style={{ position: "relative" }}>
      <input
        type={visible ? "text" : "password"}
        autoComplete={autoComplete}
        style={{ ...inputStyle, paddingRight: 46, ...style }}
        value={value}
        onChange={onChange}
        placeholder={placeholder}
      />
      <button
        type="button"
        onClick={() => setVisible((v) => !v)}
        aria-label={visible ? "Ocultar contraseña" : "Mostrar contraseña"}
        style={{
          position: "absolute",
          right: 4,
          top: "50%",
          transform: "translateY(-50%)",
          background: "none",
          border: "none",
          color: "#888",
          width: 38,
          height: 38,
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
        }}
      >
        {visible ? <EyeOff size={18} /> : <Eye size={18} />}
      </button>
    </div>
  );
}

function OnboardingWizard({ account, saveAccount, onFinish }) {
  const [step, setStep] = useState(0); // 0 bienvenida | 1 negocio | 2 trabajadores | 3 agregar a inicio | 4 listo
  const [businessName, setBusinessName] = useState(account?.businessName || "");
  const [logo, setLogo] = useState(account?.logo || "");
  const [saving, setSaving] = useState(false);
  const [addingWorker, setAddingWorker] = useState(false);
  const [workerError, setWorkerError] = useState("");
  const workers = account?.workers || [];

  async function saveBusinessStep() {
    setSaving(true);
    await saveAccount({ ...account, businessName: businessName.trim() || account?.businessName || "Mi negocio", logo: logo || account?.logo });
    setSaving(false);
    setStep(2);
  }

  async function handleSaveWorker(worker) {
    const usernameTaken = workers.some((w) => w.username.trim().toLowerCase() === worker.username.trim().toLowerCase());
    if (usernameTaken) {
      setWorkerError("Ya existe un trabajador con ese usuario. Elige otro.");
      return;
    }
    setWorkerError("");
    const next = [...workers, { ...worker, id: Date.now().toString(36) + Math.random().toString(36).slice(2, 6) }];
    await saveAccount({ ...account, workers: next });
    setAddingWorker(false);
  }

  async function handleDeleteWorker(id) {
    const next = workers.filter((w) => w.id !== id);
    await saveAccount({ ...account, workers: next });
  }

  const shellStyle = {
    minHeight: "100dvh",
    display: "flex",
    flexDirection: "column",
    padding: "28px 24px",
    boxSizing: "border-box",
  };

  const dots = (
    <div style={{ display: "flex", justifyContent: "center", gap: 7, marginBottom: 22 }}>
      {[0, 1, 2, 3, 4].map((i) => (
        <div key={i} style={{ width: i === step ? 20 : 7, height: 7, borderRadius: 4, background: i === step ? ORANGE : "#333", transition: "all 0.2s" }} />
      ))}
    </div>
  );

  if (addingWorker) {
    return (
      <div className="app-shell" style={{ background: "#0a0a0a", color: "#fff", fontFamily: "system-ui, -apple-system, sans-serif" }}>
        <style>{RESPONSIVE_STYLE}</style>
        <WorkerForm worker={null} onSave={handleSaveWorker} onCancel={() => { setAddingWorker(false); setWorkerError(""); }} error={workerError} />
      </div>
    );
  }

  return (
    <div className="app-shell" style={{ background: "#0a0a0a", color: "#fff", fontFamily: "system-ui, -apple-system, sans-serif" }}>
      <style>{RESPONSIVE_STYLE}</style>
      <div style={shellStyle}>
        {dots}

        {step === 0 && (
          <div style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", textAlign: "center" }}>
            <img src={account?.logo || DEFAULT_LOGO} alt="" style={{ width: 200, height: 200, objectFit: "contain", marginBottom: 24 }} />
            <div style={{ fontSize: 24, fontWeight: 800, marginBottom: 10 }}>¡Cuenta creada!</div>
            <div style={{ color: "#999", fontSize: 14.5, lineHeight: 1.5, marginBottom: 36, maxWidth: 320 }}>
              Vamos a dejar todo listo en unos pasos: el nombre de tu negocio y, si quieres, tu equipo de trabajo.
            </div>
            <button onClick={() => setStep(1)} style={{ width: "100%", maxWidth: 320, background: ORANGE, border: "none", borderRadius: 16, padding: "20px", color: "#fff", fontWeight: 800, fontSize: 16 }}>
              Comenzar
            </button>
          </div>
        )}

        {step === 1 && (
          <div style={{ flex: 1, display: "flex", flexDirection: "column", justifyContent: "center" }}>
            <div style={{ fontSize: 21, fontWeight: 800, marginBottom: 6, textAlign: "center" }}>Tu negocio</div>
            <div style={{ color: "#999", fontSize: 14, textAlign: "center", marginBottom: 26 }}>¿Cómo se llama y cuál es tu logo?</div>

            <div style={{ display: "flex", justifyContent: "center", marginBottom: 16 }}>
              <div style={{ width: 96, height: 96, borderRadius: 20, overflow: "hidden", background: "#141414", border: `2px solid ${ORANGE}`, display: "flex", alignItems: "center", justifyContent: "center" }}>
                <img src={logo || account?.logo || DEFAULT_LOGO} alt="" style={{ width: "100%", height: "100%", objectFit: "contain" }} />
              </div>
            </div>
            <div style={{ marginBottom: 20 }}>
              <PhotoPicker onPick={setLogo} label="Cambiar logo" />
            </div>

            <Field label="Nombre del negocio">
              <input style={inputStyle} value={businessName} onChange={(e) => setBusinessName(e.target.value)} placeholder="Ej: Chefwillys" />
            </Field>

            <button onClick={saveBusinessStep} disabled={saving} style={{ ...primaryBtn, width: "100%", marginTop: 12, padding: "18px", opacity: saving ? 0.7 : 1 }}>
              {saving ? "Guardando..." : "Continuar"}
            </button>
          </div>
        )}

        {step === 2 && (
          <div style={{ flex: 1, display: "flex", flexDirection: "column" }}>
            <div style={{ fontSize: 21, fontWeight: 800, marginBottom: 6, textAlign: "center" }}>Tu equipo</div>
            <div style={{ color: "#999", fontSize: 14, textAlign: "center", marginBottom: 22 }}>
              Crea usuario y contraseña para cocina, domiciliarios, caja o administradores. Puedes hacerlo después si prefieres.
            </div>

            <div style={{ flex: 1, overflowY: "auto", marginBottom: 14 }}>
              {workers.length === 0 && (
                <div style={{ color: "#666", textAlign: "center", padding: "18px 0", fontSize: 13.5 }}>Todavía no has agregado a nadie.</div>
              )}
              {workers.map((w) => {
                const meta = WORKER_ROLE_META[w.role] || WORKER_ROLE_META.cocina;
                return (
                  <div key={w.id} style={{ background: "#141414", borderRadius: 12, padding: 12, marginBottom: 8, display: "flex", alignItems: "center", gap: 10 }}>
                    <div style={{ width: 36, height: 36, borderRadius: w.photo ? "50%" : 9, overflow: "hidden", background: meta.bg, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 16, flexShrink: 0 }}>
                      {w.photo ? <img src={w.photo} alt="" style={{ width: "100%", height: "100%", objectFit: "cover" }} /> : meta.icon}
                    </div>
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <div style={{ fontWeight: 700, fontSize: 13.5 }}>{w.name}</div>
                      <div style={{ color: "#999", fontSize: 11.5 }}>@{w.username} · {meta.label}</div>
                    </div>
                    <button onClick={() => handleDeleteWorker(w.id)} style={{ background: "none", border: "none", color: "#f87171", width: 30, height: 30, display: "flex", alignItems: "center", justifyContent: "center" }}>
                      <Trash2 size={15} />
                    </button>
                  </div>
                );
              })}
            </div>

            <button
              onClick={() => setAddingWorker(true)}
              style={{ width: "100%", background: "#1a1a1a", border: `2px solid ${ORANGE}`, borderRadius: 14, padding: "15px", color: "#fff", fontWeight: 700, fontSize: 14.5, marginBottom: 10, display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}
            >
              <Plus size={17} /> Agregar trabajador
            </button>
            <button onClick={() => setStep(3)} style={{ ...primaryBtn, width: "100%", padding: "18px" }}>
              {workers.length > 0 ? "Continuar" : "Omitir por ahora"}
            </button>
          </div>
        )}

        {step === 3 && (
          <div style={{ flex: 1, display: "flex", flexDirection: "column" }}>
            <div style={{ fontSize: 21, fontWeight: 800, marginBottom: 6, textAlign: "center" }}>Agrega la app a tu pantalla de inicio</div>
            <div style={{ color: "#999", fontSize: 14, textAlign: "center", marginBottom: 18, lineHeight: 1.4 }}>
              Así se abre como una app normal, con ícono propio y en pantalla completa — sin escribir la dirección cada vez.
            </div>

            <div style={{ flex: 1, overflowY: "auto" }}>
              <HomeScreenTutorial businessName={businessName || account?.businessName || "Chefwillys"} logo={logo || account?.logo} />
            </div>

            <button onClick={() => setStep(4)} style={{ ...primaryBtn, width: "100%", marginTop: 14, padding: "18px", display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}>
              Continuar <ChevronLeft size={18} style={{ transform: "rotate(180deg)" }} />
            </button>
          </div>
        )}

        {step === 4 && (
          <div style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", textAlign: "center" }}>
            <div style={{ fontSize: 60, marginBottom: 18 }}>🎉</div>
            <div style={{ fontSize: 22, fontWeight: 800, marginBottom: 10 }}>¡Todo listo!</div>
            <div style={{ color: "#999", fontSize: 14.5, lineHeight: 1.5, marginBottom: 36, maxWidth: 300 }}>
              Ya puedes abrir tu turno y empezar a vender. Siempre puedes ajustar todo esto después desde Ajustes.
            </div>
            <button onClick={onFinish} style={{ width: "100%", maxWidth: 320, background: ORANGE, border: "none", borderRadius: 16, padding: "20px", color: "#fff", fontWeight: 800, fontSize: 16 }}>
              🔓 Empezar a vender
            </button>
          </div>
        )}
      </div>
    </div>
  );
}


function AuthScreens({ authView, setAuthView, authError, hasAccount, onRegister, onLogin, onWorkerLogin, businessName }) {
  const [entryMode, setEntryMode] = useState("choose"); // choose | admin | worker

  return (
    <div className="app-shell" style={{ background: "#0a0a0a", minHeight: "100dvh", color: "#fff", fontFamily: "system-ui, -apple-system, sans-serif", display: "flex", flexDirection: "column", justifyContent: "center", padding: "20px 24px", boxSizing: "border-box" }}>
      <style>{RESPONSIVE_STYLE}</style>
      <div style={{ textAlign: "center", marginBottom: 26 }}>
        <img
          src={DEFAULT_LOGO}
          alt="Chefwillys"
          style={{ width: 170, height: 170, objectFit: "contain", margin: "0 auto 10px", display: "block" }}
        />
        <div style={{ fontSize: 22, fontWeight: 800 }}>CHEF<span style={{ color: ORANGE }}>WILLYS</span></div>
        <div style={{ fontSize: 11, color: "#888", letterSpacing: 2 }}>PUNTO DE VENTA</div>
      </div>

      {entryMode === "choose" && (
        <div>
          <div style={{ color: "#999", fontSize: 14, textAlign: "center", marginBottom: 18 }}>¿Cómo vas a entrar?</div>
          <button
            onClick={() => setEntryMode("admin")}
            style={{ width: "100%", background: ORANGE, border: "none", borderRadius: 14, padding: "18px", color: "#fff", fontWeight: 800, fontSize: 16, marginBottom: 12, display: "flex", alignItems: "center", justifyContent: "center", gap: 10 }}
          >
            <Lock size={20} /> Administrador General
          </button>
          <button
            onClick={() => setEntryMode("worker")}
            style={{ width: "100%", background: "#1a1a1a", border: `2px solid ${ORANGE}`, borderRadius: 14, padding: "18px", color: "#fff", fontWeight: 800, fontSize: 16, display: "flex", alignItems: "center", justifyContent: "center", gap: 10 }}
          >
            👥 Trabajadores
          </button>
        </div>
      )}

      {entryMode === "admin" && (
        <div>
          {authView === "login" ? (
            <LoginForm onSubmit={onLogin} error={authError} hasAccount={hasAccount} onSwitch={() => setAuthView("register")} />
          ) : (
            <RegisterForm onSubmit={onRegister} error={authError} onSwitch={() => setAuthView("login")} />
          )}
          <button onClick={() => setEntryMode("choose")} style={{ display: "block", margin: "18px auto 0", background: "none", border: "none", color: "#888", fontSize: 13 }}>
            ← Volver
          </button>
        </div>
      )}

      {entryMode === "worker" && (
        <div>
          <WorkerLoginForm onSubmit={onWorkerLogin} error={authError} />
          <button onClick={() => setEntryMode("choose")} style={{ display: "block", margin: "18px auto 0", background: "none", border: "none", color: "#888", fontSize: 13 }}>
            ← Volver
          </button>
        </div>
      )}
    </div>
  );
}

function WorkerLoginForm({ onSubmit, error }) {
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [submitting, setSubmitting] = useState(false);

  async function submit() {
    if (submitting) return;
    setSubmitting(true);
    await onSubmit(username, password);
    setSubmitting(false);
  }

  return (
    <form onSubmit={(e) => { e.preventDefault(); submit(); }}>
      <div style={{ color: "#999", fontSize: 14, textAlign: "center", marginBottom: 16 }}>
        Ingresa el usuario y la contraseña que te dio tu administrador.
      </div>

      <Field label="Usuario">
        <input
          autoCapitalize="none"
          autoCorrect="off"
          autoComplete="username"
          style={inputStyle}
          value={username}
          onChange={(e) => setUsername(e.target.value)}
        />
      </Field>
      <Field label="Contraseña">
        <PasswordInput autoComplete="current-password" value={password} onChange={(e) => setPassword(e.target.value)} />
      </Field>
      {error && <div style={{ color: "#f87171", fontSize: 13, marginBottom: 12 }}>{error}</div>}
      <button type="submit" disabled={submitting} style={{ ...primaryBtn, width: "100%", marginTop: 4, opacity: submitting ? 0.7 : 1 }}>
        Entrar
      </button>
    </form>
  );
}

function LoginForm({ onSubmit, error, hasAccount, onSwitch }) {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [submitting, setSubmitting] = useState(false);

  async function submit() {
    if (submitting) return;
    setSubmitting(true);
    await onSubmit(email, password);
    setSubmitting(false);
  }

  return (
    <form onSubmit={(e) => { e.preventDefault(); submit(); }}>
      <Field label="Correo electrónico">
        <input
          type="email"
          inputMode="email"
          autoCapitalize="none"
          autoCorrect="off"
          autoComplete="email"
          style={inputStyle}
          value={email}
          onChange={(e) => setEmail(e.target.value)}
        />
      </Field>
      <Field label="Contraseña">
        <PasswordInput autoComplete="current-password" value={password} onChange={(e) => setPassword(e.target.value)} />
      </Field>
      {error && <div style={{ color: "#f87171", fontSize: 13, marginBottom: 12 }}>{error}</div>}
      <button type="submit" disabled={submitting} style={{ ...primaryBtn, width: "100%", marginTop: 4, opacity: submitting ? 0.7 : 1 }}>
        {submitting ? "Entrando..." : "Iniciar sesión"}
      </button>
      <div style={{ textAlign: "center", marginTop: 16, fontSize: 13, color: "#999" }}>
        {hasAccount ? "¿No tienes cuenta? " : "Crea tu cuenta para empezar: "}
        <button type="button" onClick={onSwitch} style={{ background: "none", border: "none", color: ORANGE, fontWeight: 700 }}>Crear cuenta</button>
      </div>
    </form>
  );
}

function RegisterForm({ onSubmit, error, onSwitch }) {
  const [email, setEmail] = useState("");
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [submitting, setSubmitting] = useState(false);

  async function submit() {
    if (submitting) return;
    setSubmitting(true);
    await onSubmit(email, username, password);
    setSubmitting(false);
  }

  return (
    <form onSubmit={(e) => { e.preventDefault(); submit(); }}>
      <Field label="Correo electrónico">
        <input
          type="email"
          inputMode="email"
          autoCapitalize="none"
          autoCorrect="off"
          autoComplete="email"
          required
          pattern="[^\s@]+@[^\s@]+\.[a-zA-Z]{2,}"
          style={inputStyle}
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          placeholder="nombre@correo.com"
        />
      </Field>
      <Field label="Usuario"><input autoComplete="username" style={inputStyle} value={username} onChange={(e) => setUsername(e.target.value)} /></Field>
      <Field label="Contraseña">
        <PasswordInput autoComplete="new-password" value={password} onChange={(e) => setPassword(e.target.value)} />
      </Field>
      {error && <div style={{ color: "#f87171", fontSize: 13, marginBottom: 12 }}>{error}</div>}
      <button type="submit" disabled={submitting} style={{ ...primaryBtn, width: "100%", marginTop: 4, opacity: submitting ? 0.7 : 1 }}>
        {submitting ? "Creando cuenta..." : "Crear cuenta"}
      </button>
      <div style={{ textAlign: "center", marginTop: 16, fontSize: 13, color: "#999" }}>
        ¿Ya tienes cuenta?{" "}
        <button type="button" onClick={onSwitch} style={{ background: "none", border: "none", color: ORANGE, fontWeight: 700 }}>Iniciar sesión</button>
      </div>
    </form>
  );
}
